import defusedxml.ElementTree as ET

def parse_xml_config(xml_file):
    tree = ET.parse(xml_file, ET.XMLParser(huge_tree=True))
    root = tree.getroot()
    
    config_dict = {}
    for elem in root:
        if elem.tag not in config_dict:
            config_dict[elem.tag] = {}
        
        if elem.text is not None:
            config_dict[elem.tag][elem.attrib['name']] = elem.text
    
    return config_dict